import React from 'react';
import { DEFAULT_CUE_ANCHOR_ACTIVATION_OPTIONS } from './scrollCueAnchor';
import { type CueCalloutState, useCueCallout } from './useCueCallout';
import { useScrollCueAnchorWhenActive } from './useScrollCueAnchorWhenActive';

export type CueCalloutProps = {
  children: (state: CueCalloutState) => React.ReactNode;
  manageFocus?: boolean;
  scrollIntoView?: boolean;
};

const CueCallout = ({
  children,
  manageFocus = DEFAULT_CUE_ANCHOR_ACTIVATION_OPTIONS.manageFocus,
  scrollIntoView = DEFAULT_CUE_ANCHOR_ACTIVATION_OPTIONS.scrollIntoView,
}: CueCalloutProps) => {
  const state = useCueCallout();
  const setAnchorRef = useScrollCueAnchorWhenActive(state.isActive, {
    manageFocus,
    scrollIntoView,
  });

  return (
    <div data-cue-callout ref={setAnchorRef}>
      {children(state)}
    </div>
  );
};

export default CueCallout;
